import{_ as e,o as a,c as s,a0 as o}from"./chunks/framework.CrGeEOPE.js";const y=JSON.parse('{"title":"qbuem-json Test Case Documentation & Integrity Report","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://qbuem.com/qbuem-json/TEST_CASES.html"}]]},"headers":[],"relativePath":"TEST_CASES.md","filePath":"TEST_CASES.md"}'),r={name:"TEST_CASES.md"};function i(l,t,n,d,c,g){return a(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="qbuem-json-test-case-documentation-integrity-report" tabindex="-1">qbuem-json Test Case Documentation &amp; Integrity Report <a class="header-anchor" href="#qbuem-json-test-case-documentation-integrity-report" aria-label="Permalink to &quot;qbuem-json Test Case Documentation &amp; Integrity Report&quot;">​</a></h1><p>This document outlines the systematic testing methodology and standard compliance verification for the qbuem-json library.</p><h2 id="_1-testing-philosophy" tabindex="-1">1. Testing Philosophy <a class="header-anchor" href="#_1-testing-philosophy" aria-label="Permalink to &quot;1. Testing Philosophy&quot;">​</a></h2><p>qbuem-json follows a &quot;Safety First, Performance Second&quot; philosophy. Every feature is validated against memory sanitizers and official RFC test suites to ensure that extreme performance does not come at the cost of correctness or security.</p><p><strong>Total test count: 507</strong> (as of the ReproBugs2 + Observations additions).</p><h2 id="_2-core-compliance-standard-verification" tabindex="-1">2. Core Compliance &amp; Standard Verification <a class="header-anchor" href="#_2-core-compliance-standard-verification" aria-label="Permalink to &quot;2. Core Compliance &amp; Standard Verification&quot;">​</a></h2><p>These tests guarantee that qbuem-json flawlessly adheres to official JSON standards.</p><h3 id="_2-1-rfc-8259-compliance-json" tabindex="-1">2.1 RFC 8259 Compliance (JSON) <a class="header-anchor" href="#_2-1-rfc-8259-compliance-json" aria-label="Permalink to &quot;2.1 RFC 8259 Compliance (JSON)&quot;">​</a></h3><ul><li><strong>File</strong>: <code>tests/test_compliance.cpp</code></li><li><strong>Objective</strong>: Flawless adherence to the official JSON specification.</li><li><strong>Coverage</strong>: <ul><li>All valid JSON values (Acceptance tests).</li><li>All invalid JSON values (Rejection tests - e.g. trailing commas, leading zeros).</li><li>Deep structures and edge-case numbers.</li></ul></li></ul><h3 id="_2-2-rfc-6901-json-pointer" tabindex="-1">2.2 RFC 6901 (JSON Pointer) <a class="header-anchor" href="#_2-2-rfc-6901-json-pointer" aria-label="Permalink to &quot;2.2 RFC 6901 (JSON Pointer)&quot;">​</a></h3><ul><li><strong>File</strong>: <code>tests/test_compliance.cpp</code></li><li><strong>Objective</strong>: Standardized navigation within a JSON document.</li><li><strong>Features</strong>: <ul><li><code>~0</code> and <code>~1</code> escape sequences.</li><li><code>-</code> (end of array) token handling.</li><li>Leading zero restriction in array indices.</li></ul></li></ul><h3 id="_2-3-rfc-6902-json-patch" tabindex="-1">2.3 RFC 6902 (JSON Patch) <a class="header-anchor" href="#_2-3-rfc-6902-json-patch" aria-label="Permalink to &quot;2.3 RFC 6902 (JSON Patch)&quot;">​</a></h3><ul><li><strong>File</strong>: <code>tests/test_compliance.cpp</code></li><li><strong>Objective</strong>: Transactional DOM modification via standard patch arrays.</li><li><strong>Supported Operations</strong>: <code>add</code>, <code>remove</code>, <code>replace</code>, <code>move</code>, <code>copy</code>, <code>test</code>.</li></ul><hr><h2 id="_3-security-multi-sanitizer-verification-memory-integrity" tabindex="-1">3. Security &amp; Multi-Sanitizer Verification (Memory Integrity) <a class="header-anchor" href="#_3-security-multi-sanitizer-verification-memory-integrity" aria-label="Permalink to &quot;3. Security &amp; Multi-Sanitizer Verification (Memory Integrity)&quot;">​</a></h2><p>To mathematically and dynamically prove memory safety and the absence of undefined behavior, qbuem-json is continuously validated against the following sanitizers:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Sanitizer</th><th style="text-align:left;">Target</th><th style="text-align:left;">Result (macOS 15/16)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>ASan</strong> (Address)</td><td style="text-align:left;">Heap/Stack Overflows, UAF</td><td style="text-align:left;"><strong>PASS (0 errors)</strong></td></tr><tr><td style="text-align:left;"><strong>UBSan</strong> (Undefined)</td><td style="text-align:left;">Arithmetic, Alignment, Overflow</td><td style="text-align:left;"><strong>PASS (0 errors)</strong></td></tr><tr><td style="text-align:left;"><strong>TSan</strong> (Thread)</td><td style="text-align:left;">Data Races, Concurrency</td><td style="text-align:left;"><strong>PASS (0 errors)</strong></td></tr><tr><td style="text-align:left;"><strong>LSan/leaks</strong></td><td style="text-align:left;">Memory Leaks (Runtime)</td><td style="text-align:left;"><strong>PASS (0 leaks)</strong></td></tr></tbody></table><hr><h2 id="_4-performance-zero-cost-audit" tabindex="-1">4. Performance &amp; Zero-Cost Audit <a class="header-anchor" href="#_4-performance-zero-cost-audit" aria-label="Permalink to &quot;4. Performance &amp; Zero-Cost Audit&quot;">​</a></h2><p>qbuem-json adheres to the &quot;Zero-Cost&quot; principle: you don&#39;t pay for the mutation features unless you use them.</p><ul><li><strong>Read-Path Efficiency</strong>: Accessors like <code>operator[]</code> and <code>at()</code> use <code>QBUEM_UNLIKELY</code> branch hints to check for mutations. For read-only documents, this cost is a single bit-check.</li><li><strong>Throughput Verification</strong> (Release build, twitter.json): <ul><li><strong>Parsing</strong>: ~227 μs (<strong>2.7 GB/s</strong>)</li><li><strong>Serialization</strong>: ~75 μs (<strong>8.1 GB/s</strong>)</li></ul></li><li><strong>No Regressions</strong>: Comparisons against the baseline show 0% performance loss on cold-path (read-only) usage after RFC 6901/6902 integration.</li></ul><h2 id="_5-security-multi-sanitizer-verification" tabindex="-1">5. Security &amp; Multi-Sanitizer Verification <a class="header-anchor" href="#_5-security-multi-sanitizer-verification" aria-label="Permalink to &quot;5. Security &amp; Multi-Sanitizer Verification&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Sanitizer</th><th style="text-align:left;">Target</th><th style="text-align:left;">Result</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>ASan</strong></td><td style="text-align:left;">Memory Errors</td><td style="text-align:left;"><strong>PASS</strong></td></tr><tr><td style="text-align:left;"><strong>UBSan</strong></td><td style="text-align:left;">Undefined Behavior</td><td style="text-align:left;"><strong>PASS</strong></td></tr><tr><td style="text-align:left;"><strong>TSan</strong></td><td style="text-align:left;">Data Races</td><td style="text-align:left;"><strong>PASS</strong></td></tr><tr><td style="text-align:left;"><strong>Leaks</strong></td><td style="text-align:left;">Memory Leaks</td><td style="text-align:left;"><strong>PASS (0 byte)</strong></td></tr></tbody></table><hr><h2 id="_6-regression-bug-fix-test-suites" tabindex="-1">6. Regression &amp; Bug-Fix Test Suites <a class="header-anchor" href="#_6-regression-bug-fix-test-suites" aria-label="Permalink to &quot;6. Regression &amp; Bug-Fix Test Suites&quot;">​</a></h2><h3 id="_6-1-reprobugs2-suite-—-tests-repro-bugs-cpp" tabindex="-1">6.1 ReproBugs2 Suite — <code>tests/repro_bugs.cpp</code> <a class="header-anchor" href="#_6-1-reprobugs2-suite-—-tests-repro-bugs-cpp" aria-label="Permalink to &quot;6.1 ReproBugs2 Suite — `tests/repro_bugs.cpp`&quot;">​</a></h3><p>10 regression tests covering the four bugs fixed in v1.0.x:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Test</th><th style="text-align:left;">Bug</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ParseReusePublicFacade</code></td><td style="text-align:left;">BUG-1</td><td style="text-align:left;"><code>qbuem::parse_reuse()</code> is available in the public <code>qbuem::</code> namespace without ADL ambiguity</td></tr><tr><td style="text-align:left;"><code>UnsignedIntSubscriptNoAmbiguity</code></td><td style="text-align:left;">BUG-2</td><td style="text-align:left;"><code>Value::operator[](unsigned int)</code> compiles and dispatches correctly</td></tr><tr><td style="text-align:left;"><code>UnsignedIntEraseNoAmbiguity</code></td><td style="text-align:left;">BUG-2</td><td style="text-align:left;"><code>Value::erase(unsigned int)</code> compiles and dispatches correctly</td></tr><tr><td style="text-align:left;"><code>SafeValueGetUnsignedIntNoAmbiguity</code></td><td style="text-align:left;">BUG-2</td><td style="text-align:left;"><code>SafeValue::operator[](unsigned int)</code> and <code>SafeValue::get(unsigned int)</code> compile correctly</td></tr><tr><td style="text-align:left;"><code>PushBackSizeReflectsNewElements</code></td><td style="text-align:left;">BUG-3</td><td style="text-align:left;"><code>size()</code> on an array returns <code>tape_count + push_back_count</code></td></tr><tr><td style="text-align:left;"><code>PushBackOnNonEmptyArraySizeCorrect</code></td><td style="text-align:left;">BUG-3</td><td style="text-align:left;"><code>size()</code> correct after <code>push_back()</code> on a non-empty parsed array</td></tr><tr><td style="text-align:left;"><code>PushBackJsonSizeReflectsNewElements</code></td><td style="text-align:left;">BUG-3</td><td style="text-align:left;"><code>size()</code> correct after <code>push_back_json()</code></td></tr><tr><td style="text-align:left;"><code>ItemsIncludesInsertedKeys</code></td><td style="text-align:left;">BUG-4</td><td style="text-align:left;"><code>items()</code> iteration yields keys added via <code>insert()</code></td></tr><tr><td style="text-align:left;"><code>ItemsIncludesInsertedKeysAfterErase</code></td><td style="text-align:left;">BUG-4</td><td style="text-align:left;"><code>items()</code> correctly handles erased tape keys mixed with inserted keys</td></tr><tr><td style="text-align:left;"><code>ItemsValuesOfInsertedKeys</code></td><td style="text-align:left;">BUG-4</td><td style="text-align:left;">Values of <code>insert()</code>ed keys are correctly retrieved via <code>items()</code></td></tr></tbody></table><h3 id="_6-2-observations-suite-—-tests-repro-bugs-cpp" tabindex="-1">6.2 Observations Suite — <code>tests/repro_bugs.cpp</code> <a class="header-anchor" href="#_6-2-observations-suite-—-tests-repro-bugs-cpp" aria-label="Permalink to &quot;6.2 Observations Suite — `tests/repro_bugs.cpp`&quot;">​</a></h3><p>7 tests covering API behaviour clarifications (OBS-1 to OBS-3):</p><table tabindex="0"><thead><tr><th style="text-align:left;">Test</th><th style="text-align:left;">OBS</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>UnsetRevertsToOriginalValue</code></td><td style="text-align:left;">OBS-1</td><td style="text-align:left;"><code>unset()</code> restores the original parsed value, not null</td></tr><tr><td style="text-align:left;"><code>UnsetTypeNameRetainsOriginalType</code></td><td style="text-align:left;">OBS-1</td><td style="text-align:left;"><code>type_name()</code> returns original type after <code>unset()</code></td></tr><tr><td style="text-align:left;"><code>SubscriptMissReturnsInvalidNotThrow</code></td><td style="text-align:left;">OBS-2</td><td style="text-align:left;"><code>operator[]</code> on missing key returns invalid <code>Value{}</code>, does not throw</td></tr><tr><td style="text-align:left;"><code>AsOnInvalidValueThrows</code></td><td style="text-align:left;">OBS-2</td><td style="text-align:left;"><code>.as&lt;T&gt;()</code> on an invalid <code>Value</code> throws <code>std::runtime_error</code></td></tr><tr><td style="text-align:left;"><code>AsArrayThrowsOnTypeMismatch</code></td><td style="text-align:left;">OBS-3</td><td style="text-align:left;"><code>.as_array&lt;T&gt;()</code> throws on element type mismatch</td></tr><tr><td style="text-align:left;"><code>TryAsArrayHandlesMixedTypes</code></td><td style="text-align:left;">OBS-3</td><td style="text-align:left;"><code>.try_as_array&lt;T&gt;()</code> returns <code>std::nullopt</code> on type mismatch (no throw)</td></tr><tr><td style="text-align:left;"><code>TryAsArrayNeverThrows</code></td><td style="text-align:left;">OBS-3</td><td style="text-align:left;"><code>.try_as_array&lt;T&gt;()</code> never throws even with all wrong-type elements</td></tr></tbody></table><h3 id="_5-1-mutation-security-stress-test" tabindex="-1">5.1 Mutation Security Stress Test <a class="header-anchor" href="#_5-1-mutation-security-stress-test" aria-label="Permalink to &quot;5.1 Mutation Security Stress Test&quot;">​</a></h3><p>A dedicated stress test (<code>test_patch_security.cpp</code>) validates that:</p><ul><li>Unknown patch operations are rejected.</li><li>Invalid paths or out-of-bounds indices trigger safe rollbacks.</li><li>Empty paths (root targets) are handled correctly.</li><li>Cross-document <code>move</code>/<code>copy</code> operations are lifetime-safe.</li></ul>',34)])])}const h=e(r,[["render",i]]);export{y as __pageData,h as default};
